// Vérifie la clé secrète passée en header X-Alliance-Secret
const secret = $getEnvironmentVariable('ALLIANCE_WEBHOOK_SECRET');
const received = $request.headers['x-alliance-secret'] || $request.headers['X-Alliance-Secret'];
if (secret && received !== secret) {
  throw new Error('Clé secrète invalide');
}

const body = $input.first().json.body || $input.first().json;
const pageId = body.pageId || body.data?.id || body.id;
if (!pageId) {
  throw new Error('pageId manquant dans le webhook');
}
return [{ json: { pageId, raw: body } }];

// Récupère les données de la page Notion via l'API
const token = $getEnvironmentVariable('NOTION_TOKEN');
const pageId = $input.first().json.pageId;
const res = await $httpRequest({
  method: 'GET',
  url: `https://api.notion.com/v1/pages/${pageId}`,
  headers: {
    'Authorization': `Bearer ${token}`,
    'Notion-Version': '2022-06-28'
  }
});
return [{ json: { pageId, properties: res.properties } }];

const p = $input.first().json.properties;
const getText = (prop) => {
  if (!prop) return '';
  if (prop.title) return prop.title.map(t => t.plain_text).join('');
  if (prop.rich_text) return prop.rich_text.map(t => t.plain_text).join('');
  return '';
};
const getSelect = (prop) => prop?.select?.name || '';
const getCheckbox = (prop) => prop?.checkbox === true;
const getFileUrl = (prop) => {
  if (!prop?.files?.length) return '';
  const f = prop.files[0];
  return f.external?.url || f.file?.url || '';
};

const slug = getText(p.Slug);
const published = getCheckbox(p.Publié);
if (!published) {
  throw new Error("La ressource n'est pas publiée. Arrêt.");
}
return [{
  json: {
    pageId: $input.first().json.pageId,
    slug,
    title: getText(p.Titre),
    module: getSelect(p.Module),
    description: getText(p.Description),
    resourceUrl: getFileUrl(p.ressource),
    exerciceUrl: getFileUrl(p.Exercice),
    solutionUrl: getFileUrl(p['Solution exercice'])
  }
}];

const token = $getEnvironmentVariable('GITHUB_TOKEN');
const owner = $getEnvironmentVariable('GITHUB_OWNER') || 'david72220';
const repo = $getEnvironmentVariable('GITHUB_REPO') || 'alliance-digitale-formations';
const payload = $input.first().json;

const res = await $httpRequest({
  method: 'POST',
  url: `https://api.github.com/repos/${owner}/${repo}/actions/workflows/notion-publish.yml/dispatches`,
  headers: {
    'Authorization': `Bearer ${token}`,
    'Accept': 'application/vnd.github+json',
    'X-GitHub-Api-Version': '2022-11-28'
  },
  body: {
    ref: 'main',
    inputs: {
      page_id: payload.pageId,
      slug: payload.slug
    }
  }
});
return [{ json: { triggered: true, githubResponse: res } }];
